+/// One layer of a DIT butterfly network, using a slice of twiddle factors for direct indexed access.
+///
+/// Unlike `dit_layer` which takes a cloneable iterator (re-advanced per block),
+/// this version takes a `&[F]` slice and accesses twiddles by direct index per block row-pair.
+/// This avoids iterator clone overhead and enables the compiler to see the contiguous
+/// memory access pattern for better optimization.
+///
+/// Correctness: For a submat starting at absolute block offset `submat_block_offset` within
+/// the full matrix, each block `b` in the submat uses `twiddles[b * half_block_size .. (b+1) * half_block_size]`.
+/// Since the twiddle iterator was previously cloned from position 0 for each block in `dit_layer`,
+/// and the `first_half_general` submats each have `(1 << mid) / block_size` blocks with the same
+/// twiddles starting from index 0, we replicate that behavior: each block uses
+/// `twiddles[0..half_block_size]`.
+fn dit_layer_slice<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+
+    // Each block uses twiddles[0..half_block_size] (same for every block, since the original
+    // dit_layer clones the iterator from position 0 for each block).
+    let block_twiddles = &twiddles[..half_block_size];
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (lo, hi, twiddle) in izip!(
+            lows.chunks_mut(width),
+            highs.chunks_mut(width),
+            block_twiddles.iter()
+        ) {
+            DitButterfly(*twiddle).apply_to_rows(lo, hi);
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
